import React, { useEffect, useState } from 'react';

export default function LastUpdated() {
  const [lastUpdatedDate, setLastUpdatedDate] = useState(null);

  useEffect(() => {
    fetch(
      'https://api.github.com/repos/thepaulstella/thepaulstella.github.io/branches/master'
    ).then(res => {
      if (!res.ok) return;
      res.json().then(json => {
        setLastUpdatedDate(new Date(json.commit.commit.author.date).toString());
      });
    });
  }, []);

  return (
    <div>
      {lastUpdatedDate ? (
        <div className="last-updated">
          <div>Site Last Updated:</div>
          <div>{lastUpdatedDate}</div>
        </div>
      ) : (
        <div></div>
      )}
    </div>
  );
}



